);

const back = (
  <div className="space-y-3 text-center">
    <p className="text-purple-400 text-sm font-semibold uppercase tracking-widest">Founder</p>
    <p className="text-neutral-300 text-sm leading-relaxed">Full-stack engineer building UniqueUI.</p>
    <div className="flex gap-3 justify-center">
      <a href="#" className="text-xs text-purple-400 hover:underline">GitHub</a>
      <a href="#" className="text-xs text-purple-400 hover:underline">Twitter</a>
